  try {g.remove_commandEvent(on$GridReport$ExecuteCommand);} catch (ex) {}
}
function on$GridReport$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, id = g.get_id(), msg = (g._language == 'v' ? 'Chưa có bản ghi nào được chọn, phải đánh dấu trước khi thực hiện chức năng này.' : 'No record selected, please select at least one record to process.');
  switch (action) {
