    g._activeRow = g._rowCount;
    g._activeColumn = g._$t;
    g._activeCell = g._getItem(g._activeRow, g._activeColumn);
    g._focusWhenTabChanged();
  }
}
function row$Key(g, r, c) {if (c == g._$y) {return g._getItemValue(r, c).z.format('yyyyMMdd');} else {return g._getItemValue(r, c);}}
function onChange$SelectedValue(o) {
  var a = o.id.split('_inputCell_'), g = o.grid;
  if (!g) g = $find(a[0]);
  var r = $func.getLocationCell(o)[0];
  var k = row$Key(g, r, g._$i), l = '', m = row$Key(g, r, g._$y), n = row$Key(g, r, g._$z), i = Array.indexOf(g._$k, k);
  if (i == -1) Array.add(g._$k, k), Array.add(g._$ld, l), Array.add(g._$lvd, m), Array.add(g._$c, n);
    else Array.removeAt(g._$k, i), Array.removeAt(g._$ld, i), Array.removeAt(g._$lvd, i), Array.removeAt(g._$c, i);

  g._activeRow = a[1].split('.')[0];
  g._activeColumn = a[1].split('.')[1];
  g._activeCell = g._getItem(g._activeRow, g._activeColumn);
}
function beforeDrillDown(g) {g._args.cancelEvent = !($func.trim(g._getItemValue(g._activeRow, g._activeColumn)));}
